import{_ as t,o as e,c as r,a2 as o}from"./chunks/framework.Crpw6aS5.js";const p=JSON.parse('{"title":"格雷迪·罗西尔","description":"","frontmatter":{"title":"格雷迪·罗西尔"},"headers":[],"relativePath":"04_people/格雷迪·罗西尔.md","filePath":"04_people/格雷迪·罗西尔.md"}'),l={name:"04_people/格雷迪·罗西尔.md"};function n(d,a,i,h,c,s){return e(),r("div",null,[...a[0]||(a[0]=[o('<h1 id="格雷迪·罗西尔-grady-rosier" tabindex="-1">格雷迪·罗西尔（Grady Rosier） <a class="header-anchor" href="#格雷迪·罗西尔-grady-rosier" aria-label="Permalink to &quot;格雷迪·罗西尔（Grady Rosier）&quot;">​</a></h1><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th>项目</th><th>内容</th></tr></thead><tbody><tr><td><strong>姓名</strong></td><td>Grady Rosier（格雷迪·罗西尔）</td></tr><tr><td><strong>职位</strong></td><td>McLane Company CEO</td></tr><tr><td><strong>关联公司</strong></td><td>McLane Company</td></tr><tr><td><strong>首次提及</strong></td><td>2003年</td></tr></tbody></table><h2 id="与巴菲特的故事" tabindex="-1">与巴菲特的故事 <a class="header-anchor" href="#与巴菲特的故事" aria-label="Permalink to &quot;与巴菲特的故事&quot;">​</a></h2><p>格雷迪·罗西尔是McLane公司的CEO，将这家从沃尔玛收购的分销巨头打造为伯克希尔旗下最成功的企业之一。</p><h3 id="从沃尔玛收购" tabindex="-1">从沃尔玛收购 <a class="header-anchor" href="#从沃尔玛收购" aria-label="Permalink to &quot;从沃尔玛收购&quot;">​</a></h3><p>2003年，高盛董事总经理拜伦·特罗特告诉巴菲特，沃尔玛希望出售其McLane子公司。巴菲特如此描述交易过程：</p><blockquote><p>&quot;McLane的销售额约为230亿美元，但利润率极薄——税前约1%——将使伯克希尔的销售额数字增长远超我们的收入。过去，一些零售商因McLane由其主要竞争对手拥有而回避它。格雷迪·罗西尔（McLane出色的CEO）已经争取到了其中一些客户——他在交易完成当天就全力以赴——还会有更多客户。&quot;（2003年股东信）</p></blockquote><blockquote><p>&quot;为达成McLane交易，我与沃尔玛首席财务官汤姆·肖伊韦开了一次约两小时的会议，然后我们握手。二十九天后，沃尔玛收到了钱。我们没有做&#39;尽职调查&#39;。&quot;（2003年股东信）</p></blockquote><h3 id="业绩卓越" tabindex="-1">业绩卓越 <a class="header-anchor" href="#业绩卓越" aria-label="Permalink to &quot;业绩卓越&quot;">​</a></h3><p>收购后，McLane在格雷迪的领导下持续创造辉煌业绩：</p><blockquote><p>&quot;McLane，我们由Grady Rosier经营的大型分销公司，在2011年增加了重要的新客户，并创下3.7亿美元的税前收益纪录。自2003年以15亿美元购买以来，该公司税前收益24亿美元。&quot;（2011年股东信）</p></blockquote><blockquote><p>&quot;2010年，格雷迪·罗西尔的McLane进入了葡萄酒和烈酒分销业务，以补充其320亿美元的食品产品、香烟、糖果和杂货分销业务。&quot;（2010年股东信）</p></blockquote><h3 id="业务拓展" tabindex="-1">业务拓展 <a class="header-anchor" href="#业务拓展" aria-label="Permalink to &quot;业务拓展&quot;">​</a></h3><p>格雷迪不断推动McLane的业务边界，从传统的食品和日用品分销扩展到葡萄酒和烈酒领域，展现了出色的战略眼光和执行力。</p><h2 id="关联年份" tabindex="-1">关联年份 <a class="header-anchor" href="#关联年份" aria-label="Permalink to &quot;关联年份&quot;">​</a></h2><p>2003, 2004, 2010, 2011</p><h2 id="相关链接" tabindex="-1">相关链接 <a class="header-anchor" href="#相关链接" aria-label="Permalink to &quot;相关链接&quot;">​</a></h2><ul><li><a href="./../03_公司库/McLane.html">McLane Company</a> - 管理的公司</li><li><a href="./../03_公司库/伯克希尔哈撒韦.html">伯克希尔·哈撒韦</a> - 母公司</li></ul><hr><p><em>最后更新：2026-04-09</em></p><h2 id="相关信件" tabindex="-1">相关信件 <a class="header-anchor" href="#相关信件" aria-label="Permalink to &quot;相关信件&quot;">​</a></h2><ul><li><a href="./../01_letters/2003年/翻译.html">2003年</a></li><li><a href="./../01_letters/2009年/翻译.html">2009年</a></li></ul>',23)])])}const _=t(l,[["render",n]]);export{p as __pageData,_ as default};
